      double u=fabs(x - (w/2.0))/(w/2.0); // 0 at center, 1 at edges
      double v=(double)y/h;
      int r,g,b;
      if(y < 850){
        // Sky: symmetric in x, increases with y; B constant 255
        double Rv = 146.0 + 28.0*v + 13.0*u; // tuned to match samples
        double Gv = 190.0 + 25.0*v + 7.0*u;
        double Bv = 255.0;
        r=(int)round(Rv); g=(int)round(Gv); b=(int)round(Bv);
      } else {
        // Ground: checkerboard stripes across 600-pixel tiles and ~100-pixel vertical bands
        int xtile = x/600; int ytile = (y-850)/100; if(ytile<0) ytile=0;
        int base = ((xtile + ytile) & 1) ? 152 : 67;
        r=g=b=base;
        // Central circular overlay around (cx,cy)
        double dx=x-cx, dy=y-cy; double d=hypot(dx,dy);
        if(d < R){
          double t = 1.0 - d/R; // 1 at center -> 0 at edge
          int rr = (int)round(51.0*t + r*(1.0-t));
          int gg = (int)round(10.0*t + g*(1.0-t));
          int bb = (int)round(10.0*t + b*(1.0-t));
          r=rr; g=gg; b=bb;
          if(y>1100){ // darken lower part toward 20,20,20
            double q = fmin(1.0, (y-1100)/200.0);
            r = (int)round(r*(1.0-q) + 20.0*q);
            g = (int)round(g*(1.0-q) + 20.0*q);
            b = (int)round(b*(1.0-q) + 20.0*q);
          }
        }
      }
      if(r<0)r=0; if(g<0)g=0; if(b<0)b=0; if(r>255)r=255; if(g>255)g=255; if(b>255)b=255;
      fprintf(f,"%d %d %d\n",r,g,b);
    }
  }
  fclose(f); return 0;
}
EOF
